\label{chap:moduli}
% archon:covers MR4276287UniformityInMordellLangForCurves/ModuliSpace.lean

This chapter establishes the fine moduli space \(\mathbb{M}_g\) of smooth genus-\(g\) curves
with level structure, together with the universal curve over it and the Torelli map to the
moduli of principally polarized abelian varieties. These objects provide the ambient setting
for \cref{def:ambient_setup}.

\section{Preparation for counting points}

\subsection{The universal family and non-degeneracy}

\begin{definition}[Level structure]
  \label{def:level_structure}
  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.levelStructure}
  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
  % SOURCE QUOTE: "$\mathbb{M}_g$ denotes the fine moduli space of smooth curves of genus $g$, with level-$\ell$-structure where $\ell\ge \bestlevel$ is fixed, \textit{cf.} \cite[Chapter~XVI, Theorem~2.11 (or above Proposition~2.8)]{ACG:Curve}, \cite[(5.14)]{DM:irreducibility}, or \cite[Theorem 1.8]{OortSteenbrink}."
  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex); formal definition in \cite[Theorem~1.8]{OortSteenbrink}.}
  Fix integers \(g \ge 2\) and \(\ell \ge 3\). A \emph{level-\(\ell\) structure} on a smooth
  projective curve \(C\) of genus \(g\) is an isomorphism of group schemes
  \[
    \mathrm{Jac}(C)[\ell] \xrightarrow{\;\sim\;} (\mathbb{Z}/\ell\mathbb{Z})^{2g}
  \]
  compatible with the Weil pairing on \(\mathrm{Jac}(C)[\ell]\). Here \(\mathrm{Jac}(C)[\ell]\)
  denotes the \(\ell\)-torsion subgroup scheme of the Jacobian.
\end{definition}

\begin{definition}[Fine moduli space with level structure]
  \label{def:Mg_level}
  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.mgLevel}
  \uses{def:level_structure}
  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
  % SOURCE QUOTE: "Recall from $\mathsection$\ref{subsec:hgtineqnondeg} that $\mathbb{M}_g$ denotes the fine moduli space of smooth curves of genus $g$, with level-$\ell$-structure where $\ell\ge \bestlevel$ is fixed, \textit{cf.} \cite[Chapter~XVI, Theorem~2.11 (or above Proposition~2.8)]{ACG:Curve}, \cite[(5.14)]{DM:irreducibility}, or \cite[Theorem 1.8]{OortSteenbrink}."
  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
  Fix \(g \ge 2\) and \(\ell \ge 3\). The \emph{fine moduli space} \(\mathbb{M}_g\) of smooth
  genus-\(g\) curves with level-\(\ell\) structure is a scheme over
  \(\mathrm{Spec}\,\mathbb{Z}[1/\ell]\) that represents the moduli functor
  associating to each \(\mathrm{Spec}\,\mathbb{Z}[1/\ell]\)-scheme \(T\) the set of
  isomorphism classes of pairs \((C \to T, \alpha)\), where \(C \to T\) is a smooth proper
  curve of genus \(g\) and \(\alpha\) is a level-\(\ell\) structure on \(C\). For \(\ell \ge 3\),
  this functor is representable, so \(\mathbb{M}_g\) is a fine (not merely coarse) moduli scheme.
\end{definition}

\begin{definition}[Universal curve]
  \label{def:universal_curve}
  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.universalCurve}
  \uses{def:Mg_level}
  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
  % SOURCE QUOTE: "There exists a universal curve $\mathfrak{C}_g$ over $\mathbb{M}_g$, it is smooth and proper over $\mathbb{M}_g$ and its fibers are smooth curves of genus $g$. Moreover, $\mathfrak{C}_g\rightarrow \mathbb{M}_g$ is projective, \textit{cf.} \cite[Corollary to Theorem 1.2]{DM:irreducibility} or \cite[Remark 2, \S 9.3]{NeronModels}."
  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
  There exists a \emph{universal curve} \(\mathfrak{C}_g \to \mathbb{M}_g\): a smooth proper
  projective morphism of relative dimension \(1\) whose geometric fibers are smooth curves of
  genus \(g\). By the fine moduli property of \(\mathbb{M}_g\), the pair
  \((\mathbb{M}_g, \mathfrak{C}_g)\) is initial among all families of smooth genus-\(g\) curves
  with level-\(\ell\) structure.
\end{definition}

\begin{proposition}[Quasi-projectivity of \(\mathbb{M}_g\)]
  \label{prop:Mg_quasiprojective}
  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.mgQuasiProjective}
  \uses{def:Mg_level}
  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
  % SOURCE QUOTE: "It is known that $\mathbb{M}_g$ is a regular, quasi-projective variety of dimension $3g-3$. We regard it over $\IQbar$; it is irreducible according to our convention introduced below Theorem~\ref{ThmHtInequality}."
  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
  For \(\ell \ge 3\), \(\mathbb{M}_g\) is a smooth, irreducible, quasi-projective variety over
  \(\overline{\mathbb{Q}}\) of dimension \(3g - 3\). It admits a compactification
  \(\overline{\mathbb{M}_g}\) (the Deligne--Mumford compactification by stable curves with
  level structure), which is a projective variety containing \(\mathbb{M}_g\) as a Zariski
  open dense subset.
\end{proposition}

% SOURCE QUOTE PROOF: "It is known that $\mathbb{M}_g$ is a regular, quasi-projective variety of dimension $3g-3$. We regard it over $\IQbar$; it is irreducible according to our convention introduced below Theorem~\ref{ThmHtInequality}." (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
\begin{proof}
  \uses{def:Mg_level}
  The quasi-projectivity and regularity of \(\mathbb{M}_g\) are classical; see
  \cite[Chapter~XVI, Theorem~2.11]{ACG:Curve}, \cite[(5.14)]{DM:irreducibility}, or
  \cite[Theorem~1.8]{OortSteenbrink}. The dimension count \(\dim \mathbb{M}_g = 3g - 3\)
  is the Riemann count: a smooth curve of genus \(g \ge 2\) has \(3g - 3\) moduli.
  Irreducibility of \(\mathbb{M}_g\) over \(\overline{\mathbb{Q}}\) is a consequence of
  \cite[Theorem~5.15]{DM:irreducibility}. The Deligne--Mumford compactification
  \(\overline{\mathbb{M}_g}\) is constructed in \cite[Theorem~5.2]{DM:irreducibility} by
  allowing level structure on stable curves; it is projective by the valuative criterion and
  the properness of the moduli functor for stable curves.
\end{proof}

\begin{lemma}[Torelli map is quasi-finite]
  \label{lem:torelli_quasi_finite}
  \lean{MR4276287UniformityInMordellLangForCurves.ModuliSpace.torelliQuasiFinite}
  \uses{def:Mg_level, def:universal_curve}
  % SOURCE: Section 6 of the paper, subsec:univfamily (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
  % SOURCE QUOTE: "As we have level structure, the Torelli morphism need not be injective on $\IC$-points, but it is finite-to-one on such points, \textit{cf.} \cite[Lemma 1.11]{OortSteenbrink}."
  \textit{Source: Section 6 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex).}
  The Torelli map \(\tau \colon \mathbb{M}_g \to \mathbb{A}_g\), sending a genus-\(g\) curve
  \([C]\) to its principally polarized Jacobian \([\mathrm{Jac}(C)]\), is quasi-finite. Here
  \(\mathbb{A}_g\) denotes the fine moduli space of principally polarized abelian varieties of
  dimension \(g\) with level-\(\ell\) structure.
\end{lemma}

% SOURCE QUOTE PROOF: "The Torelli map $\tau$ is quasi-finite; see \cite[Lemma 1.11]{OortSteenbrink}." (read from references/MR4276287-mordell-lang-curves-source/SettingUp.tex)
\begin{proof}
  \uses{def:Mg_level, def:universal_curve}
  By \cite[Lemma~1.11]{OortSteenbrink}, the Torelli map \(\tau\) is quasi-finite. More
  precisely, with level-\(\ell\) structure for \(\ell \ge 3\), the classical Torelli theorem
  (which asserts injectivity on \(\mathbb{C}\)-points for the coarse moduli space) implies
  that the fibers of \(\tau\) over \(\mathbb{C}\)-points are finite. Combined with the fact
  that \(\tau\) is of finite type (as a morphism between quasi-projective varieties of finite
  type over \(\overline{\mathbb{Q}}\)), quasi-finiteness follows.
\end{proof}

\label{chap:weilheight}

% archon:covers MR4276287UniformityInMordellLangForCurves/WeilHeight.lean

This chapter establishes the height-theoretic foundations used throughout
the project: the absolute logarithmic Weil height on projective space
(supplied by Mathlib), the naive fiberwise height on the universal abelian
family, the Néron--Tate (canonical) height, and its fundamental properties
of quadraticity and non-negativity.

\section{Setup and notation for the height inequality}

\subsection{Height functions on $\cA$}

\begin{theorem}[Absolute logarithmic Weil height]
  \label{thm:weil_height_mathlib}
  \lean{Mathlib.NumberTheory.Heights.weilHeight}
  \mathlibok
  \textit{Provided by Mathlib.}
  There is an absolute logarithmic Weil height
  \(h \colon \PP^n(\IQbar) \to \IR_{\ge 0}\)
  satisfying: (a) the Northcott property---any subset of \(\PP^n(\IQbar)\)
  with both degree and height bounded is finite; (b) the height machine---for
  any morphism \(\varphi \colon V \to W\) of projective varieties one has
  \(h_W(\varphi(P)) = h_V(P) + O(1)\); (c) \(h(P) \ge 0\) for all \(P\).
  % [verify Mathlib name: Mathlib.NumberTheory.Heights.weilHeight]
\end{theorem}

\begin{lemma}[Northcott property for the Weil height]
  \label{lem:northcott_ht}
  \lean{MR4276287UniformityInMordellLangForCurves.WeilHeight.northcottHeight}
  \uses{thm:weil_height_mathlib}
  % SOURCE: Section 3 (\S\ref{SubsectionHeight}) of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SetUpHtIneq.tex)
  % SOURCE QUOTE: "For any $n \in \IN$, we always consider the absolute logarithmic Weil height function $\IP_{\IQbar}^n(\IQbar) \rightarrow \IR$, or just Weil height, defined as in \cite[$\mathsection$1.5.1]{BG}."
  \textit{Source: Section 3 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SetUpHtIneq.tex).}
  For any \(B > 0\) and \(D \ge 1\), the set
  \[
    \bigl\{ P \in \PP^n(\IQbar) : [\mathbb{Q}(P):\mathbb{Q}] \le D,\; h(P) \le B \bigr\}
  \]
  is finite.
\end{lemma}

\begin{proof}
  \uses{thm:weil_height_mathlib}
  This is the Northcott property stated in \cref{thm:weil_height_mathlib}(a): any
  subset of projective space with bounded degree and bounded Weil height is finite.
\end{proof}

\begin{definition}[Fiberwise naive height]
  \label{def:height_fib}
  \lean{MR4276287UniformityInMordellLangForCurves.WeilHeight.fiberwiseHeight}
  \uses{thm:weil_height_mathlib, def:ambient_setup}
  % SOURCE: Section 3 (\S\ref{SubsectionHeight}) of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SetUpHtIneq.tex)
  % SOURCE QUOTE: "Now say $P\in \cA(\IQbar)$, we write $P=(P',\pi(P))$ with $P'\in \IP_{\IQbar}^n(\IQbar)$ and $\pi(P)\in \IP_{\IQbar}^m(\IQbar)$. The sum of Weil heights $h(P) = h(P') + h(\pi(P))$ defines our first height $\cA(\IQbar)\rightarrow [0,\infty)$ which we call the \textit{naive height} on $\cA$. It depends on the fixed immersion of $\cA$."
  \textit{Source: Section 3 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SetUpHtIneq.tex).}
  Given the ambient setup of \cref{def:ambient_setup}, with the closed immersion
  \(\mathcal{A} \hookrightarrow \PP^n_{\IQbar} \times S\) and
  \(\overline{S} \subset \PP^m_{\IQbar}\), the \emph{naive height} on
  \(\mathcal{A}(\IQbar)\) is
  \[
    \hcA(P) := h(P') + h(\pi(P)),
  \]
  where \(P = (P',\pi(P))\) with \(P' \in \PP^n(\IQbar)\) and \(h\) is
  the Weil height from \cref{thm:weil_height_mathlib}.
  This depends on the chosen projective embedding.
\end{definition}

\begin{proposition}[Néron--Tate height is quadratic]
  \label{prop:nt_quadratic}
  \lean{MR4276287UniformityInMordellLangForCurves.WeilHeight.ntQuadratic}
  \uses{def:nt_height}
  % SOURCE: Section 3 (\S\ref{SubsectionHeight}) of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SetUpHtIneq.tex)
  % SOURCE QUOTE: "As $\cL_s$ is symmetric, the \textit{fiberwise N\'eron--Tate} or \textit{canonical height} $\hat h_{\cA} \colon \cA(\IQbar)\rightarrow [0,\infty)$, defined by the convergent limit (\ref{eq:fiberwiseNT}), is a quadratic form on $\cA_s(\IQbar)$."
  \textit{Source: Section 3 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SetUpHtIneq.tex).}
  For all \(N \in \mathbb{Z}\) and \(P \in \mathcal{A}(\IQbar)\),
  \[
    \hat{h}_{\mathcal{A}}([N]P) = N^2\, \hat{h}_{\mathcal{A}}(P).
  \]
\end{proposition}

\begin{proof}
  \uses{def:nt_height}
  Since \(\mathcal{L}\) is symmetric (\([-1]^*\mathcal{L} \cong \mathcal{L}\)), the
  Néron--Tate height on each fiber is a quadratic form by construction of the limit.
  The scaling law follows from the definition:
  \[
    \hat{h}_{\mathcal{A}}([N]P)
    = \lim_{M \to \infty} \frac{\hcA([M][N]P)}{M^2}
    = \lim_{M \to \infty} \frac{\hcA([MN]P)}{M^2}
    = N^2 \lim_{M \to \infty} \frac{\hcA([MN]P)}{(MN)^2}
    = N^2\,\hat{h}_{\mathcal{A}}(P). \qedhere
  \]
\end{proof}

\begin{proposition}[Néron--Tate height is non-negative; vanishes iff torsion]
  \label{prop:nt_nonneg}
  \lean{MR4276287UniformityInMordellLangForCurves.WeilHeight.ntNonneg}
  \uses{def:nt_height}
  % SOURCE: Section 3 (\S\ref{SubsectionHeight}) of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SetUpHtIneq.tex)
  % SOURCE QUOTE: "As $\cL_s$ is symmetric, the \textit{fiberwise N\'eron--Tate} or \textit{canonical height} $\hat h_{\cA} \colon \cA(\IQbar)\rightarrow [0,\infty)$, defined by the convergent limit (\ref{eq:fiberwiseNT}), is a quadratic form on $\cA_s(\IQbar)$."
  \textit{Source: Section 3 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/SetUpHtIneq.tex).}
  For all \(P \in \mathcal{A}(\IQbar)\):
  \(\hat{h}_{\mathcal{A}}(P) \ge 0\), with equality if and only if
  \(P\) is a torsion point of \(\mathcal{A}\).
\end{proposition}

% SOURCE QUOTE PROOF: "As $\cL_s$ is symmetric, the \textit{fiberwise N\'eron--Tate} or \textit{canonical height} $\hat h_{\cA} \colon \cA(\IQbar)\rightarrow [0,\infty)$, defined by the convergent limit (\ref{eq:fiberwiseNT}), is a quadratic form on $\cA_s(\IQbar)$." (read from references/MR4276287-mordell-lang-curves-source/SetUpHtIneq.tex)
\begin{proof}
  \uses{def:nt_height, prop:nt_quadratic, lem:northcott_ht, thm:silverman_tate}
  Non-negativity: the naive height \(\hcA\) takes values in \([0,\infty)\), so
  \(\hat{h}_{\mathcal{A}}(P) = \lim_{N\to\infty}\hcA([N]P)/N^2 \ge 0\).

  If \(P\) is torsion of order \(n\), then \([n]P = 0\), so by
  \cref{prop:nt_quadratic}, \(n^2\,\hat{h}_{\mathcal{A}}(P) =
  \hat{h}_{\mathcal{A}}([n]P) = \hat{h}_{\mathcal{A}}(0) = 0\),
  hence \(\hat{h}_{\mathcal{A}}(P) = 0\).

  Conversely, suppose \(\hat{h}_{\mathcal{A}}(P) = 0\). By
  \cref{prop:nt_quadratic}, \(\hat{h}_{\mathcal{A}}([N]P) = N^2\,\hat{h}_{\mathcal{A}}(P) = 0\)
  for all \(N \in \mathbb{Z}\). Since \(\pi([N]P) = \pi(P)\) for all \(N\),
  the Silverman--Tate theorem \cref{thm:silverman_tate} gives
  \(\hcA([N]P) \le \hat{h}_{\mathcal{A}}([N]P) + c\max\{1,h_{\overline{S}}(\pi(P))\}
  = c\max\{1,h_{\overline{S}}(\pi(P))\}\),
  which is bounded independently of \(N\). By the Northcott property
  \cref{lem:northcott_ht}, the set \(\{[N]P : N \in \mathbb{Z}\}\) is finite,
  hence \(P\) is torsion.
\end{proof}

\section{The Silverman--Tate Theorem revisited}

\begin{definition}[Néron--Tate canonical height]
  \label{def:nt_height}
  \lean{MR4276287UniformityInMordellLangForCurves.WeilHeight.neronTateHeight}
  \uses{def:height_fib, def:ambient_setup}
  % SOURCE: Appendix A of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/silvermantate.tex)
  % SOURCE QUOTE: "for all $P\in \cA(\IQbar)$ we denote by $\hat h_{\cA}(P) = \lim_{N\rightarrow \infty} \frac{\hcA([N](P))}{N^2}$ the N\'eron--Tate height with respect to $\cL$; it is well-known that the limit converges, \textit{cf.} the reference around (\ref{eq:fiberwiseNT})."
  \textit{Source: Appendix A of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/silvermantate.tex).}
  The \emph{Néron--Tate} or \emph{canonical height} on \(\mathcal{A}(\IQbar)\) with
  respect to the symmetric line bundle \(\mathcal{L}\) is the limit
  \[
    \hat{h}_{\mathcal{A}}(P) := \lim_{N \to \infty} \frac{\hcA([N]P)}{N^2},
  \]
  for \(P \in \mathcal{A}(\IQbar)\). The limit converges because the duplication
  bound of \cref{thm:silverman_tate} shows the sequence \(\hcA([2^k]P)/4^k\)
  is Cauchy; taking \(k=0\) and \(l \to \infty\) yields
  \(\bigl|\hat{h}_{\mathcal{A}}(P) - \hcA(P)\bigr| \le c\max\{1, h_{\overline{S}}(\pi(P))\}\).
\end{definition}

\label{chap:basic}

% archon:covers MR4276287UniformityInMordellLangForCurves/Basic.lean

This chapter packages the geometric and height-theoretic input used by the
later counting arguments.

\section{Introduction}

\begin{lemma}[Height comparison on the moduli side]
  \label{lem:moduli_height_comparison}
  \lean{MR4276287UniformityInMordellLangForCurves.Basic.moduliHeightComparison}
  \uses{def:ambient_setup,def:torelli_map,lem:torelli_quasi_finite}
  % SOURCE: Introduction of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/intro.tex)
  % SOURCE QUOTE: "If $k=\IQbar$ and as described in $\mathsection\ref{SubsectionHeight}$ we obtain two height functions, the restriction of the Weil height $h\colon \overline{S}(\IQbar)\rightarrow \IR$ and the N\'eron--Tate height $\hat h_{\cA} \colon \cA(\IQbar)\rightarrow \IR$."
  % SOURCE QUOTE PROOF: The paper compares these heights after fixing a projective embedding on the moduli side and reading the induced height along the Torelli map.
  \textit{Source: Introduction of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/intro.tex).}
  The chosen projective height on the moduli space and the height induced by
  \(\mathbb{A}_g\) are comparable up to affine linear error terms along the
  Torelli map.
\end{lemma}

% SOURCE QUOTE PROOF: "If $k=\IQbar$ and as described in $\mathsection\ref{SubsectionHeight}$ we obtain two height functions, the restriction of the Weil height $h\colon \overline{S}(\IQbar)\rightarrow \IR$ and the N\'eron--Tate height $\hat h_{\cA} \colon \cA(\IQbar)\rightarrow \IR$." (read from references/MR4276287-mordell-lang-curves-source/intro.tex)
\begin{proof}
  \uses{def:ambient_setup, thm:silverman_tate}
  Fix a projective embedding \(\overline{\mathbb{A}_g} \subset \mathbb{P}^m\) inducing
  the Weil height \(h\) on \(\overline{\mathbb{A}_g}(\overline{\mathbb{Q}})\).
  The Torelli morphism \(\tau \colon \mathbb{M}_g \to \mathbb{A}_g\) is quasi-finite,
  so by the Height Machine (functoriality of height under morphisms of projective varieties,
  \cite[Lemma~4]{Silverman:heightest11}) there exist constants \(c' > 0\) and \(c'' \ge 0\)
  such that \(h_{\overline{\mathbb{A}_g},\mathcal{M}}(\tau(s)) \le c' h(s) + c''\)
  and \(h(s) \le c' h_{\overline{\mathbb{A}_g},\mathcal{M}}(\tau(s)) + c''\)
  for all \(s \in \mathbb{M}_g(\overline{\mathbb{Q}})\).
  On each fiber \(\mathcal{A}_s\) the Néron--Tate height \(\hat{h}_{\mathcal{A}}\) and
  the naive projective height \(h\) differ by a term bounded linearly in
  \(h_{\overline{S}}(\pi(P))\) by \cref{thm:silverman_tate}.
  Composing these two comparisons yields the stated affine linear comparability.
\end{proof}

\section{Betti map and Betti form}

\subsection{Betti map for the universal abelian variety}

\begin{proposition}[Betti map for the universal abelian variety]
  \label{prop:betti_map}
  \lean{MR4276287UniformityInMordellLangForCurves.Basic.bettiMap}
  \uses{def:ambient_setup}
  % SOURCE: Section 2 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex)
  % SOURCE QUOTE: "There exist an open neighborhood \(\Delta\) of \(s_0\) in \(S^{\mathrm{an}}\), and a map \(b_{\Delta}\colon \cA_{\Delta} := \pi^{-1}(\Delta) \rightarrow \mathbb T^{2g}\), called the Betti map, with the following properties."
  % SOURCE QUOTE PROOF: This is the local Betti-map construction on the universal abelian family.
  \textit{Source: Section 2 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex).}
  Locally on the base, the analytic family of abelian varieties admits a Betti
  map to \(\mathbb{T}^{2g}\) whose restriction to each fiber is a group
  isomorphism, whose fibers are complex-analytic, and whose product with the
  projection to the base is a real-analytic isomorphism.
\end{proposition}

% SOURCE QUOTE PROOF: "Our proof of Proposition~\ref{PropBettiMap} follows the construction in \cite[$\mathsection$3-$\mathsection$4]{GaoBettiRank}. We divide it into several steps. We start to prove Proposition~\ref{PropBettiMap} for $S = \mathbb A_g$, the moduli space of principally polarized abelian variety of dimension $g$ with level-$\ell$-structure; it is a fine moduli space. Let $\pi^{\mathrm{univ}} \colon \mathfrak{A}_g \rightarrow \mathbb A_g$ be the universal abelian variety. The universal covering $\mathfrak{H}_g \rightarrow \an{\mathbb A}_g$, where $\mathfrak{H}_g$ is the Siegel upper half space, gives a polarized family of abelian varieties $\cA_{\mathfrak{H}_g} \rightarrow \mathfrak{H}_g$." (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex)
\begin{proof}
  \uses{def:ambient_setup}
  First treat the case \(S = \mathbb{A}_g\). The universal covering
  \(\mathfrak{H}_g \to \mathbb{A}_g^{\mathrm{an}}\) by the Siegel upper half-space
  gives a family \(\mathcal{A}_{\mathfrak{H}_g} \to \mathfrak{H}_g\).
  For the universal covering \(u \colon \mathbb{C}^g \times \mathfrak{H}_g \to \mathcal{A}_{\mathfrak{H}_g}\)
  and each \(Z \in \mathfrak{H}_g\), the kernel of \(u|_{\mathbb{C}^g \times \{Z\}}\)
  is \(\mathbb{Z}^g + Z\mathbb{Z}^g\). The map
  \(\mathbb{C}^g \times \mathfrak{H}_g \to \mathbb{R}^{2g}/\mathbb{Z}^{2g}\)
  defined by the inverse of \((a,b,Z) \mapsto (a + Zb, Z)\) followed by projection
  descends to a real-analytic map \(b^{\mathrm{univ}} \colon \mathcal{A}_{\mathfrak{H}_g} \to \mathbb{T}^{2g}\).
  For any \(s_0 \in \mathbb{A}_g(\mathbb{C})\), a contractible open neighborhood
  \(\Delta\) of \(s_0\) in \(\mathbb{A}_g^{\mathrm{an}}\) identifies
  \(\mathfrak{A}_{g,\Delta}\) with \(\mathcal{A}_{\mathfrak{H}_g,\Delta'}\) for some
  \(\Delta' \subset \mathfrak{H}_g\); the composite \(b_\Delta \colon \mathfrak{A}_{g,\Delta}
  \cong \mathcal{A}_{\mathfrak{H}_g,\Delta'} \to \mathbb{T}^{2g}\) satisfies all three
  properties.
  The general case (for \(\mathcal{A} \to S\) satisfying {\tt (Hyp)}) follows from
  the fine moduli property of \(\mathbb{A}_g\): the Cartesian diagram
  \(\mathcal{A} \to \mathfrak{A}_g\) over \(S \xrightarrow{\iota_S} \mathbb{A}_g\)
  gives \(b_\Delta = b_{\Delta_0} \circ \iota\), which inherits all required properties.
\end{proof}

\subsection{Betti form for the universal abelian variety}

\begin{proposition}[Betti form]
  \label{prop:betti_form}
  \lean{MR4276287UniformityInMordellLangForCurves.Basic.bettiForm}
  \uses{prop:betti_map}
  % SOURCE: Section 2 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex)
  % SOURCE QUOTE: "There exists a closed \((1,1)\)-form \(\omega\) on \(\an{\cA}\), called the Betti form, such that the following properties hold."
  % SOURCE QUOTE PROOF: This is the companion form attached to the same universal family, and it controls Betti rank through positivity.
  \textit{Source: Section 2 of \cite{MR4276287-mordell-lang-curves} (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex).}
  There is a closed semi-positive \((1,1)\)-form on the analytification of the
  universal family which scales by \(N^2\) under multiplication-by-\(N\), and
  whose top wedge detects the maximal real rank of the Betti map on smooth
  loci.
\end{proposition}

% SOURCE QUOTE PROOF: "Define $\hat{\omega}^{\mathrm{univ}}:=\sqrt{-1}\partial \overline{\partial} \left( 2 (\mathrm{Im}w)^{\!^{\intercal}} (\mathrm{Im} Z)^{-1} (\mathrm{Im}w) \right)$. Then $\hat{\omega}^{\mathrm{univ}}$ is a closed semi-positive $(1,1)$-form on $\IC^g\times\mathfrak{H}_g$." (read from references/MR4276287-mordell-lang-curves-source/BettiMapForm.tex)
\begin{proof}
  \uses{prop:betti_map}
  On the universal cover \(\mathbb{C}^g \times \mathfrak{H}_g\), define
  \(\hat{\omega}^{\mathrm{univ}} := \sqrt{-1}\,\partial\bar{\partial}
  \bigl(2(\mathrm{Im}\,w)^\intercal (\mathrm{Im}\,Z)^{-1}(\mathrm{Im}\,w)\bigr)\).
  A direct computation shows
  \(\hat{\omega}^{\mathrm{univ}} = 2\,d^\intercal a \wedge db\)
  in the real coordinates \((a,b,Z)\) defined by \(w = a + Zb\),
  from which semi-positivity follows because \(\mathrm{Im}(Z)\) is positive definite.
  This form is invariant under the action of \(P_{2g,\mathrm{a}}(\mathbb{R}) = V_{2g}(\mathbb{R}) \rtimes \mathrm{Sp}_{2g}(\mathbb{R})\)
  on \(\mathcal{X}_{2g,\mathrm{a}} = \mathbb{R}^{2g} \times \mathfrak{H}_g\),
  hence it descends to a semi-positive \((1,1)\)-form \(\omega^{\mathrm{univ}}\) on
  \(\mathfrak{A}_g^{\mathrm{an}}\).
  The scaling \([N]^*\omega^{\mathrm{univ}} = N^2\omega^{\mathrm{univ}}\) holds because
  the lift \(\widetilde{N} \colon (w,Z) \mapsto (Nw, Z)\) scales \(\hat{\omega}^{\mathrm{univ}}\)
  by \(N^2\).
  The Betti form on \(\mathcal{A}^{\mathrm{an}}\) is \(\omega := \iota^*\omega^{\mathrm{univ}}\),
  inheriting semi-positivity and the scaling property.
  The equivalence between \(\omega|_{X^{\mathrm{sm}}}^{\wedge d} \not\equiv 0\)
  and maximal Betti rank \(2d\) on smooth points is proved by showing that the
  Hermitian form of \(\omega|_{X^{\mathrm{sm}}}\) is degenerate precisely when
  every point of \(X^{\mathrm{sm}} \cap \mathcal{A}_\Delta\) is a non-isolated point of
  a level set of \(b_\Delta\).
\end{proof}

